import { useMemo, useState } from "react";
import { GetRetType, RetType, SpotterResponseResultSchema } from "../type";
import { useMount } from "./lifecycle";

type LoadingModel = Record<React.Key, boolean>;

export const DEFAULT_LOADING_KEY = 'default_loading_key';

/**
 * 高级请求封装，更方便的读取loading数据及data属性，提供更自由的loading操作
 * @param request 请求方法
 * @returns 
 */
export const useRequest = <T extends (...args: any[]) => Promise<any>>(request: T) => {
    const [loadingMap, setLoadingMap] = useState<LoadingModel>({
        [DEFAULT_LOADING_KEY]: false,
    } as LoadingModel);
    type RetDataModel = GetRetType<T>;
    const [data, setData] = useState<RetDataModel>();

    const updateLoading = (status: boolean, id: React.Key = DEFAULT_LOADING_KEY) => {
        setLoadingMap({
            ...loadingMap,
            [id]: status
        })
    }

    const getLoading = (id: React.Key = DEFAULT_LOADING_KEY) => {
        return loadingMap[id];
    }

    const loading = useMemo(() => loadingMap[DEFAULT_LOADING_KEY] as boolean, [loadingMap]);

    const send = (args: Parameters<T>[0], loadId: React.Key = DEFAULT_LOADING_KEY): Promise<RetType<T>> => {
        return new Promise((resolve, reject) => {
            updateLoading(true, loadId);
            request(args)
                .then((res) => {
                    setData(res?.data ?? {});
                    resolve(res);
                })
                .catch((error) => reject(error))
                .finally(() => updateLoading(false, loadId));
        });
    };

    const clear = () => {
        setData({} as RetDataModel);
    };

    return {
        loading,
        data,
        setData,
        getLoading,
        clear,
        send,
    };
};

/**
 * 简化详情请求逻辑的hooks, 提供更便捷的loading及data操作
 * @param request 传递接口
 * @param payload 传递接口的参数对象
 * @returns 
 */
export const useDetail = <T extends (...args: any[]) => Promise<SpotterResponseResultSchema>>(
    request: T,
    ...payload: Parameters<T>
) => {
    const [loading, setLoading] = useState(false);
    const [detail, setDetail] = useState<GetRetType<typeof request>>();

    const fetchDetail = async (...args: any[]) => {
        const res = await request(...args);
        setDetail(res.data);
        return res;
    };

    const loadData = () => {
        setLoading(true);
        fetchDetail(...payload).finally(() => {
            setLoading(false);
        });
    }

    useMount(() => {
        loadData();
    });

    /**
     * 重置数据
     */
    const reload = () => {
        loadData();
    }

    return {
        loading,
        setLoading,
        detail,
        reload,
    };
};